// Allowlist guard + extract shared URLs from Telegram updates.
// Reuses n8n/allowlist.code.js semantics: only YOUR chat id may submit captures.
const ALLOWED_CHAT_ID = Number($env.TELEGRAM_ALLOWED_CHAT_ID);
const res = $input.first().json.result || [];
const urlRe = /(https?:\/\/[^\s]+)/g;
const out = [];
for (const u of res) {
  const msg = u.message; if (!msg) continue;
  const chatId = msg.chat?.id;
  if (chatId !== ALLOWED_CHAT_ID) { continue; } // ignore anyone but you
  const text = msg.text || '';
  const urls = text.match(urlRe) || [];
  for (const url of urls) out.push({ json: { url, chatId, update_id: u.update_id } });
}
return out;

// TODO(b): naive HTML→text — replace with a readability extractor for clean article text.
const html = String($json.data || $json.body || '');
const text = html.replace(/<script[\s\S]*?<\/script>/gi,' ').replace(/<style[\s\S]*?<\/style>/gi,' ').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim().slice(0, 12000);
return [{ json: { url: $('Guard + extract URLs').item.json.url, text } }];

// Assemble the Notesage-frontmatter capture file (see ARCHITECTURE.md 'Capture file contract').
const url = $('Extract text').item.json.url;
const summary = ($json.choices?.[0]?.message?.content || '').trim();
const title = (summary.split('
')[0] || url).replace(/^#+\s*/, '').slice(0, 120);
const body = $('Extract text').item.json.text;
const now = new Date().toISOString();
const slug = (title.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').slice(0,60) || 'capture') + '-' + Date.now();
const md = `---
title: ${JSON.stringify(title)}
source_url: ${url}
date_saved: ${now}
doc_type: capture
tags: [captured]
description: ${JSON.stringify(summary.split('
').slice(1).join(' ').slice(0,200))}
---

# ${title}

${summary}

---

${body}
`;
return [{ json: { slug, md, path: `/capture/${slug}.md` } }];
